// src/Home.js
import React from 'react';
import './Home.css';

const Home = () => {
  return (
    <section className="hero-section">
      <div className="hero-overlay"></div>
      <div className="hero-content">
        <h1 className="hero-title">
          Welcome to <span className="highlight">ProjectDuniya</span>
        </h1>
        <p className="hero-subtitle">
          Your One-Stop Platform for Academic & Technical Projects — Delivered Fast, Built to Impress.
        </p>
        <p className="hero-offer">
          🎓 500+ Projects Completed | 💼 100+ Happy Clients | 🚀 First-Time Users Get 50% OFF + Free Resume Review
        </p>
        <div className="hero-buttons">
          <a href="#services" className="btn blue-btn">Explore Services</a>
          <a
            href="https://wa.me/918391808784"
            target="_blank"
            rel="noopener noreferrer"
            className="btn green-btn"
          >
            Chat on WhatsApp
          </a>
        </div>
      </div>
    </section>
  );
};

export default Home;
